import React, { useState } from "react";
import ResultCart from "./ResultCart";

const Add = () => {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);

  function onChange(e) {
    const nextQuery = e.target.value;
    setQuery(nextQuery);

    if (!process.env.REACT_APP_TMDB_KEY) {
      // CRA'da env vars build/start anında okunur. Anahtar yoksa API 401 döner.
      console.error(
        "REACT_APP_TMDB_KEY tanımsız. .env içine TMDB API key ekleyip yeniden başlatın."
      );
      setResults([]);
      return;
    }

    fetch(
      `https://api.themoviedb.org/3/search/movie?api_key=${process.env.REACT_APP_TMDB_KEY}&language=en-US&page=1&include_adult=false&query=${nextQuery}`
    )
      .then(async (res) => {
        const data = await res.json().catch(() => ({}));

        if (!res.ok) {
          if (res.status === 401) {
            console.error("TMDB 401 Unauthorized: API key hatalı ya da eksik.");
          } else {
            console.error(`TMDB ${res.status}: istek başarısız.`);
          }
          setResults([]);
          return;
        }

        // TMDB bazı durumlarda `results` alanını dönmeyebilir. Burada mutlaka diziye çevirelim.
        const safeResults = Array.isArray(data?.results) ? data.results : [];
        setResults(data?.errors ? [] : safeResults);
      })
      .catch(() => {
        // Ağ/hata durumunda UI'nin bozulmaması için boş liste göster.
        setResults([]);
      });
  }

  return (
    <div className="add-page">
      <div className="container">
        <div className="add-content">
          <img src="https://www.themoviedb.org/t/p/w1920_and_h600_multi_faces_filter(duotone,032541,01b4e4)/9ZyAUZrfccsjtDwYgc7yvOBnqM9.jpg" />
          <div className="titles">
            <h1>Hoş Geldiniz.</h1>
            <h2>
              Milyonlarca film, TV şovu ve keşfedilecek kişi. Şimdi keşfedin.
            </h2>
          </div>
          <div className="input-wrapper">
            <input
              type="text"
              value={query}
              onChange={onChange}
              placeholder="Film, dizi, kişi ara..."
            />
          </div>

          {results.length > 0 && (
            <ul className="results">
              {results.map((movie) => (
                <li key={movie.id}>
                  <ResultCart movie={movie} />
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
};

export default Add;
